mapper.select:
SELECT celebrity_private_id, COALESCE ( JSON_ARRAYAGG( JSON_OBJECT( 'typeId', type_data.attribute_type_id, 'list', COALESCE ( ( SELECT JSON_ARRAYAGG( JSON_OBJECT( 'attributeId', cc.attribute_id, 'attributeName', cc.attribute_name, 'attributeEnName', sub_c.attribute_en_name ) ) FROM store_celebrity_private_attribute_relation cc LEFT JOIN kol_attribute sub_c ON cc.attribute_id = sub_c.id WHERE cc.celebrity_private_id = type_data.celebrity_private_id AND cc.attribute_type_id = type_data.attribute_type_id ORDER BY cc.rank ), JSON_ARRAY() ) ) ), JSON_ARRAY() ) AS dataJsonStr FROM ( SELECT celebrity_private_id, attribute_type_id, MIN( id ) AS min_id FROM store_celebrity_private_attribute_relation GROUP BY celebrity_private_id, attribute_type_id ) type_data WHERE type_data.celebrity_private_id IN
#{id}
GROUP BY type_data.celebrity_private_id

SELECT cpar.celebrity_private_id, cpar.attribute_type_id AS type_id, cpar.attribute_id, cpar.attribute_name, CASE WHEN cpar.`rank` IS NULL THEN 1 ELSE cpar.`rank` END AS `rank`, ka.attribute_en_name, 1 as is_sel FROM store_celebrity_private_attribute_relation cpar LEFT JOIN kol_attribute ka ON cpar.attribute_id = ka.id LEFT JOIN store_celebrity_private scp ON cpar.celebrity_private_id = scp.id WHERE cpar.celebrity_private_id IN
#{id}
AND ( scp.is_attribute_confirmed = 2 OR (cpar.`rank` < 4 OR cpar.`rank` IS NULL) ) ORDER BY cpar.celebrity_private_id, cpar.attribute_type_id, cpar.rank
